using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary (default: 3).
    /// </summary>
    [Range(1, 100)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "as", "it",
        "this", "that", "from", "be", "been", "being", "have", "has", "had",
        "do", "does", "did", "will", "would", "could", "should", "may",
        "might", "shall", "can", "not", "no", "so", "if", "than", "too",
        "very", "just", "about", "into", "through", "during", "before",
        "after", "above", "below", "between", "each", "which", "their",
        "there", "then", "them", "they", "these", "those", "its", "his",
        "her", "he", "she", "we", "you", "i", "me", "my", "your", "our"
    };

    public SummarizeResponse Summarize(SummarizeRequest request)
    {
        var sentences = SplitIntoSentences(request.DocumentText);

        if (sentences.Count <= request.MaxSentences)
        {
            return new SummarizeResponse
            {
                Summary = request.DocumentText.Trim(),
                OriginalSentenceCount = sentences.Count,
                SummarySentenceCount = sentences.Count
            };
        }

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scoredSentences = ScoreSentences(sentences, wordFrequencies);

        // Pick the top-scoring sentences, then reorder by original position.
        var topSentences = scoredSentences
            .OrderByDescending(s => s.Score)
            .Take(request.MaxSentences)
            .OrderBy(s => s.Index)
            .Select(s => s.Sentence)
            .ToList();

        return new SummarizeResponse
        {
            Summary = string.Join(" ", topSentences),
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = topSentences.Count
        };
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceSplitter()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word) && word.Length > 1)
                {
                    frequencies.TryGetValue(word, out var count);
                    frequencies[word] = count + 1;
                }
            }
        }

        return frequencies;
    }

    private static List<(string Sentence, int Index, double Score)> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var maxFrequency = wordFrequencies.Values.Max();

        return sentences
            .Select((sentence, index) =>
            {
                var words = ExtractWords(sentence);
                if (words.Count == 0)
                    return (sentence, index, Score: 0.0);

                var score = words
                    .Where(w => wordFrequencies.ContainsKey(w))
                    .Sum(w => wordFrequencies[w] / (double)maxFrequency);

                // Normalize by word count to avoid bias toward long sentences.
                score /= words.Count;

                return (sentence, index, Score: score);
            })
            .ToList();
    }

    private static List<string> ExtractWords(string text) =>
        WordExtractor().Matches(text).Select(m => m.Value).ToList();

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"\b[a-zA-Z]+\b", RegexOptions.Compiled)]
    private static partial Regex WordExtractor();
}

using Microsoft.AspNetCore.Mvc;
using DocSummary.Models;
